import { DatePipe, formatNumber } from "@angular/common";
import { HttpClient } from "@angular/common/http";
import { Component, OnInit } from "@angular/core";
import { FormGroup, FormBuilder } from "@angular/forms";
import { TranslateService } from "@ngx-translate/core";
import { MohassilAuthService } from "src/app/core/services/AuthenticationServices/mohassil-auth.service";
import { AlertService } from "src/app/core/services/alert.service";
import { EnvService } from "src/app/core/services/env.service";
import { IBranch } from "../../Models/References/Branch";
import { pagingService } from "src/app/core/services/paging.service";
import { sortingService } from "src/app/core/services/sorting.service";
import { UserSuspendedDocument } from "../../Models/LoanApplication/UserSuspendedDocument";
import { StaticRef } from "../../Models/References/StaticRef";
import { ReferencesService } from "src/app/core/services/references.service";

@Component({
  selector: "app-user-suspended-documents",
  templateUrl: "./user-suspended-documents.page.html",
  styleUrls: ["./user-suspended-documents.page.scss"],
})
export class UserSuspendedDocumentsPage implements OnInit {
  showLoader: boolean = false;
  details: boolean = false;

  sortingIconClass: string;
  sortingIconParam: string;

  page = 1; // the page we are viewing

  suspendedDocuments: UserSuspendedDocument[];
  FilteredDocuments: UserSuspendedDocument[];
  curDocument: UserSuspendedDocument;

  branches: IBranch[] = [];
  exceptionReasons: StaticRef[];

  SearchForm: FormGroup = this.formBuilder.group({
    client_name: [""],
    branch_code: [""],
    nation_id: [""],
  });

  constructor(
    private env: EnvService,
    private http: HttpClient,
    private formBuilder: FormBuilder,
    private datePipe: DatePipe,
    private sortingService: sortingService,
    private authService: MohassilAuthService,
    private alertService: AlertService,
    public pagingService: pagingService,
    public translate: TranslateService,
    private referenceService: ReferencesService
  ) {}

  async ngOnInit() {
    this.GetUserSuspendedDocuments();
    //Get Exception Reasons
    this.exceptionReasons = await this.referenceService.getExceptionReasons();
  }

  GetUserSuspendedDocuments() {
    this.showLoader = true;
    this.http
      .get<UserSuspendedDocument[]>(
        this.env.API_URL + `api/LoanApplications/GetUserSuspendedDocuments`
      )
      .subscribe({
        next: (data) => {
          this.suspendedDocuments = data;
          this.branches = data.reduce(
            (acc, x) => {
              const branchCode = x.branch_code.toString();
              if (!acc.set.has(branchCode)) {
                acc.set.add(branchCode);
                acc.arr.push({
                  branch_code: branchCode,
                  branch_name: x.branch_name,
                });
              }
              return acc;
            },
            { set: new Set(), arr: [] }
          ).arr;
          this.FilteredDocuments = this.suspendedDocuments;
          this.showLoader = false;
        },
        error: (error) => {
          this.alertService.showAlertError(error.error, false);
          this.showLoader = false;
        },
      });
  }

  searchForUsers() {
    this.page = 1;
    let client_name = this.SearchForm.value.client_name;
    let branch_code = this.SearchForm.value.branch_code;
    let nation_id = this.SearchForm.value.nation_id;

    this.FilteredDocuments = this.suspendedDocuments.filter(
      (v) =>
        (client_name == "" ||
          v.client_name.toLowerCase().match(client_name.toLowerCase())) &&
        (branch_code == "" || v.branch_code == branch_code) &&
        (nation_id == "" || v.nation_id?.startsWith(nation_id))
    );
  }

  showErrorMsg(errorMsg) {
    this.alertService.showAlertError(errorMsg, false);
  }

  changePage(newPage: number): void {
    this.page = newPage;
  }

  sortingTable(data: any, param: string) {
    this.sortingService.sortByParameter(data, param);
    this.sortingIconClass =
      this.sortingService.sortOrder === "asc"
        ? "arrow-down-outline"
        : "arrow-up-outline";
    this.sortingIconParam = param;
  }

  dateFormat(date) {
    return this.datePipe.transform(date, "yyyy-MM-dd");
  }

  NumberFormatStyle(number) {
    let result = formatNumber(Number(number), "en-US", "1.0");
    return result;
  }

  dismissModal() {
    this.details = false;
  }

  MoreDetails(document) {
    this.curDocument = document;
    this.details = !this.details;
  }
  async rejectApplication(exception_id: number) {
    if (await this.alertService.SaveAlert("هل تريد رفض الطلب؟")) {
    }
  }
  async UnsuspendApplication(exception_id: number) {
    if (await this.alertService.SaveAlert("هل تريد الغاء تعليق الطلب؟")) {
      this.showLoader = true;
      this.http
        .post(
          this.env.API_URL +
            `api/LoanApplications/HandleUserSuspendedDocument?exception_id=${exception_id}`,
          {}
        )
        .subscribe({
          next: () => {
            this.alertService.showAlertConfirm(
              "تم ايقاف تعليق الطلب بنجاح",
              true
            );
            this.showLoader = false;
          },
          error: (error) => {
            this.alertService.showAlertError(error.error, false);
            this.showLoader = false;
          },
        });
    }
  }
}
